// Expect either { docId: '...' } or { docUrl: '...' } plus { slug: '...' }.
const body = $input.first().json.body || $input.first().json;
let docId = (body.docId || '').trim();
const url = (body.docUrl || '').trim();
if (!docId && url) {
  const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
  if (m) docId = m[1];
}
if (!docId) throw new Error('Provide docId or docUrl');
const slug = (body.slug || '').trim();
if (!slug || !/^[a-z0-9-]+$/.test(slug)) {
  throw new Error('Provide a valid slug (lowercase, numbers, hyphens)');
}
return [{ json: { docId, slug, filename: `${slug}.json` } }];

// Parse the exported HTML body into title/meta/content/faqs.
//
// Expected Google Doc structure (just type these as plain headings/paragraphs):
//
//   Heading 1: <Article Title>
//   META: <meta description, 1 line>
//   CATEGORY: <category>          (optional)
//   IMAGE: <hero image URL>       (optional)
//   READTIME: 7 min read          (optional)
//   --- CONTENT ---
//   <main article body — uses doc paragraphs/headings>
//   --- FAQS ---
//   Q: question one?
//   A: answer one.
//   Q: question two?
//   A: answer two.
//
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0];
if (!binaryKey) throw new Error('No HTML returned from Drive');
const buf = await this.helpers.getBinaryDataBuffer(0, binaryKey);
let html = buf.toString('utf8');

// Strip Google's wrapper styles + extract body
html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
if (bodyMatch) html = bodyMatch[1];

// Plain-text helper for extracting markers
const stripTags = (s) => s.replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").trim();
const text = stripTags(html);

// Find the first H1 / first non-empty line as the title.
let title = '';
const h1 = html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
if (h1) {
  title = stripTags(h1[1]);
} else {
  title = text.split('\n').map(s => s.trim()).find(Boolean) || '';
}

const takeLine = (re) => {
  const m = text.match(re);
  return m ? m[1].trim() : '';
};
const metaDescription = takeLine(/META:\s*([^\n]+)/i);
const category = takeLine(/CATEGORY:\s*([^\n]+)/i) || 'General';
const image = takeLine(/IMAGE:\s*([^\n]+)/i);
const readTime = takeLine(/READTIME:\s*([^\n]+)/i) || '5 min read';

// Split content + faqs sections from the original HTML
const contentSplit = html.split(/---\s*CONTENT\s*---/i);
let rest = contentSplit[1] || html; // fall back to whole body if no marker
const faqSplit = rest.split(/---\s*FAQS\s*---/i);
let contentHtml = (faqSplit[0] || '').trim();
const faqBlock = (faqSplit[1] || '').trim();

// Drop the meta lines from the content if they ended up there
contentHtml = contentHtml.replace(/<p[^>]*>\s*(META|CATEGORY|IMAGE|READTIME):[^<]*<\/p>/gi, '');

// Clean Google Doc cruft a bit
contentHtml = contentHtml.replace(/\sclass=\"[^\"]*\"/g, '');
contentHtml = contentHtml.replace(/<span[^>]*>/g, '').replace(/<\/span>/g, '');

// Parse FAQs (Q:/A: alternating in plain text from the FAQ block)
const faqText = stripTags(faqBlock);
const faqs = [];
const lines = faqText.split(/\n+/).map(l => l.trim()).filter(Boolean);
let currentQ = null;
for (const line of lines) {
  if (/^Q[:.]/i.test(line)) {
    currentQ = line.replace(/^Q[:.]\s*/i, '').trim();
  } else if (/^A[:.]/i.test(line) && currentQ) {
    faqs.push({ q: currentQ, a: line.replace(/^A[:.]\s*/i, '').trim() });
    currentQ = null;
  } else if (faqs.length && !/^Q[:.]/i.test(line)) {
    // continuation of last answer
    faqs[faqs.length - 1].a += ' ' + line;
  }
}

const payload = {
  title,
  metaTitle: title,
  metaDescription,
  subtitle: metaDescription,
  category,
  date: new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
  readTime,
  image,
  content: contentHtml,
  faqs,
};

return [{ json: payload, pairedItem: { item: 0 } }];

// Convert the parsed JSON payload into a binary attachment so the
// Drive node can upload it as a real file.
const payload = $input.first().json;
const json = JSON.stringify(payload, null, 2);
const filename = $('Parse input').first().json.filename;
const binary = await this.helpers.prepareBinaryData(Buffer.from(json, 'utf8'), filename, 'application/json');
return [{ json: payload, binary: { data: binary } }];
